def detect_kb_overretrieval(response):
    if 'retrievedDocuments' not in response:
        return None

    docs = response['retrievedDocuments']
    chunk_count = len(docs)
    avg_relevance = sum(doc.get('relevanceScore', 0) for doc in docs) / chunk_count

    if chunk_count > 15 and avg_relevance < 0.7:
        return {
            'cost_waste': f'${chunk_count * 0.00045:.4f}',
            'issue': f'{chunk_count} low-relevance chunks',
            'optimization': f'Could reduce to {chunk_count//3} chunks'
        }
    return None

import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';

const client = new BedrockAgentRuntimeClient({ region: 'us-east-1' });

async function detectSessionDrift(traceEvents: any[]) {
  const memoryEvents = traceEvents.filter(e => e.type === 'agentMemory');

  if (memoryEvents.length < 2) return null;

  const currentMemory = memoryEvents[memoryEvents.length - 1].memorySnapshot;
  const prevMemory = memoryEvents[memoryEvents.length - 2].memorySnapshot;

  const memoryDelta = JSON.stringify(currentMemory) !== JSON.stringify(prevMemory);
  const turnCount = traceEvents.length;

  if (memoryDelta && turnCount > 5) {
    return {
      costImpact: `$${turnCount * 0.0025}`,
      issue: 'Session memory drift detected',
      turnsAffected: turnCount
    };
  }
  return null;
}

