            'apiPath': event['apiPath'],
            'httpStatusCode': 400,
            'responseBody': json.dumps({'error': str(e)}),
            'responseContentType': 'application/json'
        }

def optimize_kb_retrieval(query, knowledge_base_id):
    bedrock_kb = boto3.client('bedrock-agent-runtime')

    # Initial retrieval with max 20 chunks
    response = bedrock_kb.retrieve(
        knowledgeBaseId=knowledge_base_id,
        retrievalQuery={'text': query},
        retrievalConfiguration={
            'vectorSearchConfiguration': {
                'numberOfResults': 20,
                'overrideSearchType': 'HYBRID'
            }
        }
    )

    # Filter to top 5 by relevance
    filtered_docs = sorted(
        response['retrievalResults'], 
        key=lambda x: x.get('score', 0), 
        reverse=True
    )[:5]

    return {
        'retrievedDocuments': filtered_docs,
        'chunks_saved': 15,
        'cost_saved': '$0.00675'
    }

import { DynamoDBClient, PutItemCommand, GetItemCommand } from '@aws-sdk/client-dynamodb';

const ddb = new DynamoDBClient({ region: 'us-east-1' });

const SESSION_TABLE = 'BedrockAgentSessions';

export async function saveSessionState(sessionId: string, memorySnapshot: any) {
  await ddb.send(new PutItemCommand({
    TableName: SESSION_TABLE,
    Item: {
      sessionId: { S: sessionId },
      memorySnapshot: { S: JSON.stringify(memorySnapshot) },
      timestamp: { N: Date.now().toString() }
    }
  }));
}

export async function loadSessionState(sessionId: string) {
  const result = await ddb.send(new GetItemCommand({
    TableName: SESSION_TABLE,
    Key: { sessionId: { S: sessionId } }
  }));

  return result.Item?.memorySnapshot?.S ? 
    JSON.parse(result.Item.memorySnapshot.S) : {};
}
